import React, { useEffect, useState } from "react";
import CodeMirror from "@uiw/react-codemirror";
import { html } from "@codemirror/lang-html";
import { css } from "@codemirror/lang-css";
import { javascript } from "@codemirror/lang-javascript";
import "./App.css";

function App() {
  const [tab, setTab] = useState("html");

  const [htmlCode, setHtml] = useState("<h1>Hello</h1>");
  const [cssCode, setCss] = useState("h1{color:red}");
  const [jsCode, setJs] = useState("");

  // Load
  useEffect(() => {
    const data = JSON.parse(localStorage.getItem("project"));
    if (data) {
      setHtml(data.html || "");
      setCss(data.css || "");
      setJs(data.js || "");
    }
  }, []);

  // Save
  useEffect(() => {
    localStorage.setItem("project", JSON.stringify({
      html: htmlCode,
      css: cssCode,
      js: jsCode
    }));
  }, [htmlCode, cssCode, jsCode]);

  // Copy
  const copyCode = () => {
    const code =
      tab === "html" ? htmlCode :
      tab === "css" ? cssCode : jsCode;

    navigator.clipboard.writeText(code);
  };

  // Download
  const downloadCode = () => {
    const file = new Blob(
      [htmlCode + "<style>" + cssCode + "</style><script>" + jsCode + "</script>"],
      { type: "text/html" }
    );
    const a = document.createElement("a");
    a.href = URL.createObjectURL(file);
    a.download = "project.html";
    a.click();
  };

  const output = `
    <html>
      <style>${cssCode}</style>
      <body>
        ${htmlCode}
        <script>${jsCode}<\/script>
      </body>
    </html>
  `;

  const getLang = () => {
    if (tab === "html") return html();
    if (tab === "css") return css();
    return javascript();
  };

  return (
    <div className="app">

      {/* TOPBAR */}
      <div className="topbar">
        <h2>CodeSnip</h2>
        <div>
          <button onClick={copyCode}>Copy</button>
          <button onClick={downloadCode}>Download</button>
        </div>
      </div>

      {/* TABS */}
      <div className="tabs">
        <button onClick={() => setTab("html")}>HTML</button>
        <button onClick={() => setTab("css")}>CSS</button>
        <button onClick={() => setTab("js")}>JS</button>
      </div>

      {/* MAIN */}
      <div className="container">

        {/* EDITOR */}
        <div className="editor">
          <CodeMirror
            value={tab === "html" ? htmlCode : tab === "css" ? cssCode : jsCode}
            height="100%"
            extensions={[getLang()]}
            onChange={(value) => {
              if (tab === "html") setHtml(value);
              if (tab === "css") setCss(value);
              if (tab === "js") setJs(value);
            }}
          />
        </div>

        {/* PREVIEW */}
        <div className="preview">
          <iframe srcDoc={output} title="preview" sandbox="allow-scripts" />
        </div>

      </div>
    </div>
  );
}

export default App;
